# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
using System.Linq;

public class EventBookingSystemContext : DbContext
{
    public DbSet<Event> Events { get; set; }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int SeatsAvailable { get; set; }
}

public class TicketPurchaseResult
{
    public bool Success { get; set; }
    public string Message { get; set; }
}

public static async Task<TicketPurchaseResult> PurchaseTicketsAsync(EventBookingSystemContext context, int eventId, int quantity)
{
    var eventEntity = await context.Events.FindAsync(eventId);
    if (eventEntity == null) return new TicketPurchaseResult { Success = false, Message = "Event not found" };

    if (quantity <= 0) return new TicketPurchaseResult { Success = false, Message = "Invalid purchase quantity" };

    if (eventEntity.SeatsAvailable < quantity)
        return new TicketPurchaseResult { Success = false, Message = "Insufficient seats available" };

    try
    {
        await context.Database.BeginTransactionAsync();

        var updatedEvent = eventEntity with { SeatsAvailable = eventEntity.SeatsAvailable - quantity };
        context.Events.Update(updatedEvent);

        await context.SaveChangesAsync();
        await context.Database.CommitTransactionAsync();

        return new TicketPurchaseResult { Success = true, Message = "Tickets purchased successfully" };
    }
    catch (Exception ex)
    {
        await context.Database.RollbackTransactionAsync();
        return new TicketPurchaseResult { Success = false, Message = $"Error purchasing tickets: {ex.Message}" };
    }
}